import { useState, useMemo } from "react";
import { useTheme } from "../contexts/ThemeContext";
import AdminSidebar from "./AdminSidebar";
import AdminSectionSettings from "./AdminSectionSettings";
import ModerationPanel from "./ModerationPanel";
import TeacherManagement from "./TeacherManagement";

export default function AdminView({
  sections,
  pendingEvents,
  pendingConnections,
  needsRevisionEvents = [],
  needsRevisionConnections = [],
  allEvents,
  allConnections,
  allStudentAssignments,
  getSectionName,
  onClose,
  onAddSection,
  onDeleteSection,
  onRenameSection,
  onEventApproved,
  displayPeriods,
  periodsBySection,
  reassignStudentSection,
  removeStudentSection,
  user,
  userName,
  isSuperAdmin,
  teacherData,
  onImpersonate,
}) {
  const { theme } = useTheme();
  const [selectedTab, setSelectedTab] = useState("moderation");

  const pendingCount = (pendingEvents?.length || 0) + (pendingConnections?.length || 0) + (needsRevisionEvents?.length || 0) + (needsRevisionConnections?.length || 0);

  const selectedSection = useMemo(
    () => sections.find((s) => s.id === selectedTab),
    [sections, selectedTab]
  );

  // If the selected section was deleted, fall back to moderation
  const effectiveTab = (selectedSection || selectedTab === "moderation" || selectedTab === "teachers") ? selectedTab : "moderation";

  return (
    <div role="region" aria-label="Administration" style={{
      display: "flex",
      height: "calc(100vh - 140px)",
      background: theme.bg,
    }}>
      <AdminSidebar
        sections={sections}
        selectedTab={effectiveTab}
        onSelectTab={setSelectedTab}
        pendingCount={pendingCount}
        onAddSection={onAddSection}
        isSuperAdmin={isSuperAdmin}
      />

      <div style={{
        flex: 1,
        overflowY: "auto",
        background: theme.bg,
      }}>
        {effectiveTab === "moderation" ? (
          <ModerationPanel
            pendingEvents={pendingEvents}
            pendingConnections={pendingConnections}
            needsRevisionEvents={needsRevisionEvents}
            needsRevisionConnections={needsRevisionConnections}
            allEvents={allEvents}
            allConnections={allConnections}
            periods={displayPeriods}
            periodsBySection={periodsBySection}
            getSectionName={getSectionName}
            onEventApproved={onEventApproved}
            user={user}
            userName={userName}
          />
        ) : effectiveTab === "teachers" && isSuperAdmin ? (
          <TeacherManagement
            user={user}
            teacherData={teacherData}
            onImpersonate={onImpersonate}
          />
        ) : selectedSection ? (
          <AdminSectionSettings
            sectionId={selectedSection.id}
            sectionName={selectedSection.name}
            sections={sections}
            allStudentAssignments={allStudentAssignments}
            onDeleteSection={onDeleteSection}
            onRenameSection={onRenameSection}
            reassignStudentSection={reassignStudentSection}
            removeStudentSection={removeStudentSection}
          />
        ) : null}
      </div>
    </div>
  );
}
